const raw = $input.first().json;
let payload;
if (raw.body?.body && typeof raw.body.body === 'object') {
  payload = raw.body.body;
} else if (raw.body && typeof raw.body === 'object') {
  payload = raw.body;
} else {
  payload = raw;
}
const contact = payload.contact || {};
const summary = payload.summary || {};
const automationScore = payload.automationScore || {};

return {
  json: {
    reportId: payload.reportId || '',
    reportUrl: payload.reportUrl || '',
    portalUrl: payload.portalUrl || '',
    contact: contact,
    summary: summary,
    automationScore: automationScore,
    leadScore: payload.leadScore || {},
    notification: payload.notification || {},
    timestamp: payload.timestamp || new Date().toISOString(),
    email: payload.email || contact.email || '',
    company: payload.company || contact.company || ''
  }
};

const d = $input.first().json;
const c = d.contact || {};
const s = d.summary || {};
const auto = d.automationScore || {};
const reportUrl = d.reportUrl || '';
const portalUrl = d.portalUrl || '';

var autoPct = auto.percentage || 0;

var metricsTable = '<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin: 20px auto; width: 100%; max-width: 540px;">' +
  '<tr>' +
    '<td align="center" width="100%" style="padding: 0 4px;">' +
      '<table role="presentation" cellpadding="0" cellspacing="0" width="100%"><tr><td style="background: #faf5ff; padding: 18px 8px; border-radius: 8px; text-align: center;">' +
        '<div style="font-size: 26px; font-weight: 700; color: #7c3aed; line-height: 1.2;">' + autoPct + '%</div>' +
        '<div style="font-size: 11px; color: #64748b; margin-top: 4px; text-transform: uppercase; letter-spacing: 0.3px;">Automation Ready</div>' +
      '</td></tr></table>' +
    '</td>' +
  '</tr>' +
'</table>';

var emailHtml = '<div style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; max-width: 640px; margin: 0 auto; background: #f8fafc; padding: 20px;">' +
  '<div style="background: linear-gradient(135deg, #1e293b, #334155); color: white; padding: 30px; border-radius: 12px 12px 0 0;">' +
    '<h1 style="margin: 0; font-size: 24px;">Your Process Audit Report is Ready</h1>' +
    '<p style="margin: 8px 0 0; opacity: 0.8;">Prepared for ' + (c.company || c.name || '') + '</p>' +
  '</div>' +
  '<div style="background: white; padding: 30px; border-radius: 0 0 12px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">' +
    '<p style="font-size: 15px; color: #334155;">Hi ' + (c.name || 'there') + ',</p>' +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6;">Thank you for completing your process audit. Here is a snapshot of what we found:</p>' +
    metricsTable +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6; text-align: center; margin-top: 24px;">Your full report includes process flow diagrams, detailed recommendations, and a personalised 90-day roadmap.</p>' +
    '<div style="margin: 24px 0; text-align: center;">' +
      '<a href="' + reportUrl + '" style="display: inline-block; padding: 14px 40px; background: linear-gradient(135deg, #6366f1, #4f46e5); color: white; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 16px;">View Full Report</a>' +
    '</div>' +
    (portalUrl ? '<div style="margin: 16px 0 0; padding: 20px; background: #f0f9ff; border-radius: 8px; text-align: center;">' +
      '<p style="margin: 0 0 10px; font-size: 14px; color: #1e293b; font-weight: 600;">Manage all your reports in one place</p>' +
      '<p style="margin: 0 0 12px; font-size: 13px; color: #475569;">Log in to your Client Portal to view, edit, request redesigns, and track your processes.</p>' +
      '<a href="' + portalUrl + '" style="display: inline-block; padding: 10px 28px; border: 2px solid #6366f1; color: #6366f1; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 14px;">Go to Client Portal</a>' +
    '</div>' : '') +
    '<hr style="border: none; border-top: 1px solid #e2e8f0; margin: 24px 0;">' +
    '<p style="font-size: 12px; color: #94a3b8; text-align: center;">You received this because you completed a process audit. If you don\'t have a portal account yet, use the same email to sign up.</p>' +
  '</div>' +
'</div>';

return {
  json: {
    to: String(d.email || c.email || ''),
    subject: 'Your Process Audit Report is Ready',
    html: emailHtml
  }
};
